INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4f53cc16-34f9-4e60-b074-48a590339519',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elasticsearch Analyzers — Why Your Queries Miss Exact Matches$escape$,
  $escape$When you index a document, Elasticsearch runs each text field through an analyzer pipeline: character filters → tokenizer → token filters. The default `standard` analyzer lowercases and tokenizes on whitespace/punctuation, storing tokens in the inverted index — not the raw string. This means a mapping defined as `"type": "text"` with no custom analyzer will tokenize `"Apache Kafka"` into `["apache", "kafka"]`. A `term` query against `"Apache Kafka"` returns nothing because it bypasses analysis and expects an exact token match. Use `match` queries for analyzed fields — they run the same analyzer at query time. For exact lookups (IDs, enums, status fields), map them as `"keyword"`. For fields needing both, use multi-fields: `text` for full-text search, `keyword` sub-field for exact match and aggregations. Aggregations like `terms` always operate on `keyword` — running them on a `text` field raises a `fielddata` error unless you explicitly enable it (avoid this in production). Audit your mappings with `GET /index/_mapping` before diagnosing query bugs.$escape$,
  $escape$PUT /articles
{
  "mappings": {
    "properties": {
      "title": {
        "type": "text",
        "analyzer": "english",
        "fields": {
          "raw": { "type": "keyword" }
        }
      },
      "status": { "type": "keyword" }
    }
  }
}

GET /articles/_search
{
  "query": { "match": { "title": "inverted index" } },
  "aggs": {
    "by_status": { "terms": { "field": "status" } }
  }
}$escape$,
  $escape$bash$escape$,
