INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b4d3f439-2047-4cc4-9bda-4adbeea88b12',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elasticsearch Engineers: Why ClickHouse's MergeTree Engine Wins for OLAP$escape$,
  $escape$Elasticsearch handles aggregations by scanning documents across shards — workable for log analytics but expensive at scale. ClickHouse's MergeTree engine stores data column-by-column on disk: a GROUP BY log_level query reads only that column, skipping everything else. Compare that to ES's doc-values, which still load per-document field data for every matching hit.

Where ES uses inverted indices and BKD trees for search, ClickHouse uses sparse primary key indices with mark files for range scans. For OLAP workloads — summing metrics, counting distinct users, bucketing events by hour — ClickHouse's columnar layout means 10–100x less I/O than Elasticsearch.

Materialized views in ClickHouse behave like ES Transform jobs but execute synchronously on INSERT. Pair one with a SummingMergeTree target table to pre-aggregate at write time — reads become near-instant because the math already happened.

Mental model for ES engineers: ES index ≈ ClickHouse table, ES shard ≈ ClickHouse partition, ES segment merge ≈ ClickHouse part merge (background merges that deduplicate and collapse aggregated rows). ClickHouse won't replace Elasticsearch for full-text search, but for time-series OLAP at scale, it operates in a different efficiency class entirely.$escape$,
  $escape$-- Unlike ES bucket aggregations (computed at query time),
-- ClickHouse materializes aggregations at write time.

CREATE TABLE logs (
    ts DateTime,
    level String,
    service String
) ENGINE = MergeTree() ORDER BY (ts, level, service);

CREATE MATERIALIZED VIEW logs_hourly
ENGINE = SummingMergeTree() ORDER BY (hour, level, service)
AS SELECT toStartOfHour(ts) AS hour, level, service, count() AS hits
FROM logs GROUP BY hour, level, service;

-- Reads hit pre-aggregated rows instantly — no full scan
SELECT hour, level, sum(hits) FROM logs_hourly GROUP BY hour, level;$escape$,
