INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a0fccd51-756f-4371-8b00-27114c30b88f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elasticsearch Replication — Primary-Replica, CCR, and Consistency Trade-offs$escape$,
  $escape$Elasticsearch uses a primary-replica model within a cluster: every shard has exactly one primary (tracked by `_primary_term`) that processes all writes and fans them synchronously to replicas before acknowledging. This is strictly leader/follower — no leaderless quorum writes like Cassandra. For cross-cluster replication, CCR formalizes this pattern with explicit leader and follower indices: the follower cluster polls the leader's internal `shard_changes` API, replaying operations in sequence-number order. Follower lag is observable via `GET /_ccr/stats` under `leader_global_checkpoint` vs `follower_global_checkpoint`. The critical consistency knob is `index.write.wait_for_active_shards`: `all` gives strong durability (write fails if any replica is unavailable), `1` (default) favors availability at the cost of potential data loss on hard failure. There is no multi-leader mode — CCR is read-scale only. Writing to a follower index is blocked by design. For safe failover, always use `if_seq_no` + `if_primary_term` on updates to prevent lost-write anomalies when a primary is reassigned during a network partition.$escape$,
  $escape$# Create a CCR follower index (run on the follower cluster)
PUT /logs-follower/_ccr/follow
{
  "remote_cluster": "us-east",
  "leader_index": "logs-leader",
  "max_read_request_operation_count": 5120,
  "max_outstanding_read_requests": 12,
  "read_poll_timeout": "5m"
}

# Harden write durability on the leader
PUT /logs-leader/_settings
{ "index.write.wait_for_active_shards": "all" }

# Monitor replication lag
GET /_ccr/stats$escape$,
  $escape$bash$escape$,
