INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e9dc2ae0-06ce-4ec5-9cc6-06b653ab99c9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elasticsearch Connection Pooling — Sizing Your Transport Layer Right$escape$,
  $escape$Elasticsearch clients manage HTTP connection pools per node via the transport layer — no external pooler like PgBouncer applies here. In elasticsearch-py, each node gets its own urllib3 `HTTPConnectionPool`. The `connections_per_node` parameter caps simultaneous HTTP connections per node; the default of 10 is often too low for bulk-indexing workloads.

Undersizing the pool causes connection queuing inside urllib3 — requests block waiting for a free socket rather than failing fast or load-balancing. Oversizing wastes file descriptors and can flood the coordinating node's HTTP thread pool, triggering `es_rejected_execution_exception`.

Sizing heuristic: `connections_per_node = ceil(worker_threads / node_count) + 2`. Enable `sniff_on_start=True` so the client discovers all data nodes rather than funneling load through a single seed. After resizing, validate against `GET /_cat/thread_pool/write?v&h=name,active,queue,rejected` — if `queue` is non-zero, your ES-side thread pool is the bottleneck, not the client pool. Tune `thread_pool.write.queue_size` in `elasticsearch.yml` alongside client `connections_per_node` for end-to-end headroom.$escape$,
  $escape$from elasticsearch import Elasticsearch

es = Elasticsearch(
    hosts=["http://es-node1:9200", "http://es-node2:9200"],
    connections_per_node=20,     # urllib3 pool size per node
    sniff_on_start=True,          # discover full cluster topology
    sniff_on_node_failure=True,   # re-sniff after a node drop
    retry_on_timeout=True,
    max_retries=3,
    request_timeout=30,
)

# Inspect active HTTP connections and thread-pool pressure
print(es.cat.nodes(v=True, h="ip,name,http.current_open"))
print(es.cat.thread_pool("write", v=True, h="name,active,queue,rejected"))$escape$,
  $escape$python$escape$,
