INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b3c44b38-8dcb-48dc-901e-956bcde9f7cb',
  '00000000-0000-0000-0000-000000000001',
  $escape$Elasticsearch Monitoring — Slow Queries, Connection Counts, Replication Lag, and Storage Growth$escape$,
  $escape$Elasticsearch exposes cluster health through the `_cat` and `_nodes` APIs — use them to catch problems before they cascade. Slow queries are logged via the `index.search.slowlog.threshold.query.warn` setting (e.g., `5s`); ship these logs to a dedicated index for aggregation. For connection counts, `GET /_nodes/stats/http` returns `current_open` and `total_opened` per node — spikes in `current_open` signal connection leaks in your client pool. Replication lag isn't exposed directly, but `GET /_cat/shards?v` shows unassigned or initializing replicas; pair it with `_cluster/pending_tasks` to detect replication bottlenecks. Storage growth lives in `GET /_cat/allocation?v`, which breaks down `disk.used`, `disk.avail`, and `shards` per node — alert when any node crosses 75% (Elasticsearch's own watermark is 85%). For a unified view, poll `GET /_nodes/stats` and feed `indices.store.size_in_bytes`, `http.current_open`, and `jvm.mem.heap_used_percent` into Prometheus via `elasticsearch_exporter`.$escape$,
  $escape$GET /_nodes/stats/http,indices,jvm

# Key fields to extract and alert on:
# nodes.<id>.http.current_open        → active connections
# nodes.<id>.indices.store.size_in_bytes → storage per node
# nodes.<id>.jvm.mem.heap_used_percent   → GC pressure

GET /_cat/shards?v&h=index,shard,prirep,state,unassigned.reason
# prirep=r + state=UNASSIGNED → replication lag indicator

GET /_cat/allocation?v&h=node,disk.used,disk.avail,disk.percent,shards
# Alert threshold: disk.percent > 75$escape$,
  $escape$bash$escape$,
